def _make_session(username: str) -> str:
    sid = uuid.uuid4().hex
    payload = {"u": username, "iat": int(time.time()), "exp": int(time.time()) + SESSION_TTL_SECONDS}
    data = json.dumps(payload, separators=(",", ":")).encode("utf-8")
    token = _b64(data) + "." + sid
    return token


def _read_session(token: str | None):
    if not token or "." not in token:
        return None
    b64part, _ = token.split(".", 1)
    try:
        payload = json.loads(base64.b64decode(b64part.encode("utf-8")).decode("utf-8"))
        if int(payload.get("exp", 0)) < int(time.time()):
            return None
        return payload
    except Exception:
        return None


