def _main():
    if not (os.path.exists(CERT_FILE) and os.path.exists(KEY_FILE)):
        raise SystemExit(f"Missing signing cert/key. Set IDP_CERT_FILE/IDP_KEY_FILE. Got: {CERT_FILE}, {KEY_FILE}")
    if not (os.path.exists(TLS_CERT_FILE) and os.path.exists(TLS_KEY_FILE)):
        raise SystemExit(f"Missing TLS cert/key. Set TLS_CERT_FILE/TLS_KEY_FILE. Got: {TLS_CERT_FILE}, {TLS_KEY_FILE}")

    context = (TLS_CERT_FILE, TLS_KEY_FILE)
    app.run(host=APP_HOST, port=APP_PORT, ssl_context=context, debug=DEBUG)


if __name__ == "__main__":
    _main()